using UnityEngine;

public class RampDetection : MonoBehaviour
{
    [Header("Ramp Detection Settings")]
    [SerializeField] private Transform[] rampDetectionPoints; // Array of transforms for raycasting
    [SerializeField] private float detectionRadius = 2f;
    [SerializeField] private float minRampAngle = 80f;
    [SerializeField] private float maxRampAngle = 100f;

    private HoverBoardControl hoverBoardControl;
    private Rigidbody rb;

    private void Awake()
    {
        hoverBoardControl = GetComponentInParent<HoverBoardControl>();
        rb = GetComponentInParent<Rigidbody>();

        // Ensure that the rampDetectionPoints array has been set, otherwise log an error
        if (rampDetectionPoints == null || rampDetectionPoints.Length == 0)
        {
            Debug.LogError("RampDetectionPoints have not been assigned in the Inspector", this);
        }
    }

    private void FixedUpdate()
    {
        foreach (var detectionPoint in rampDetectionPoints)
        {
            DetectRamp(detectionPoint);
        }
    }

    private void DetectRamp(Transform detectionPoint)
    {
        // Use the provided detectionPoint for raycasting
        if (detectionPoint != null)
        {
            RaycastHit hit;
            if (Physics.Raycast(detectionPoint.position, -Vector3.up, out hit, detectionRadius))
            {
                if (hit.collider.gameObject.layer == LayerMask.NameToLayer("Ramp"))
                {
                    Vector3 rampNormalProjection = Vector3.ProjectOnPlane(hit.normal, Vector3.up);
                    float rampAngle = Vector3.Angle(detectionPoint.forward, rampNormalProjection);

                    if (rampAngle >= minRampAngle && rampAngle <= maxRampAngle)
                    {
                        AdjustHoverboard(hit, detectionPoint.name);
                    }
                }
            }
        }
    }

    private void AdjustHoverboard(RaycastHit hit, string hitPart)
    {
        // Debug log when a ramp is detected
        Debug.Log(hitPart + " detected a ramp collision");

        Vector3 rampNormal = hit.normal;
        float rampAngle = Vector3.Angle(rampNormal, Vector3.up) - 90.0f;
        Quaternion targetRotation = Quaternion.Euler(rampAngle, rb.transform.eulerAngles.y, rb.transform.eulerAngles.z);

        // Lerp the hoverboard's rotation to the target rotation
        rb.transform.rotation = Quaternion.Lerp(rb.transform.rotation, targetRotation, Time.fixedDeltaTime * 5f);

        // Set IsGrounded to true to enable hover behavior on the ramp
        hoverBoardControl.IsGrounded = true;

        // Adjust the hover height to match the ramp
        float hoverHeight = Mathf.Max(hit.distance, hoverBoardControl.hoverHeight);
        hoverBoardControl.SetHoverHeight(hoverHeight);
    }
}

