    public void AlignToRamp(Vector3 rampNormal, float lerpSpeed)
    {
        Vector3 forwardOnRamp = Vector3.Cross(rampNormal, Vector3.Cross(Vector3.up, rampNormal)).normalized;
        Quaternion targetRotation = Quaternion.LookRotation(forwardOnRamp, rampNormal);

        rb.rotation = Quaternion.Lerp(rb.rotation, targetRotation, lerpSpeed * Time.fixedDeltaTime);
    }

    // Call this method to adjust the hoverboard's behavior when on a ramp.
    public void AdjustBoardOnRamp(bool onRamp, RaycastHit hitInfo)
    {
        isOnRamp = onRamp;
        if (onRamp)
        {
            rb.angularDrag = angularDragOnRamp; // Increase drag to stabilize the board on the ramp

            Vector3 projectedForward = Vector3.ProjectOnPlane(transform.forward, Vector3.up); // Project the forward vector onto a horizontal plane
            Vector3 projectedRampDirection = Vector3.ProjectOnPlane(hitInfo.normal, Vector3.up); // Project the ramp's normal onto a horizontal plane

            // Check if we're going uphill or downhill
            if (Vector3.Angle(projectedForward, projectedRampDirection) < 90)
            {
                // We're facing uphill
                hoverForce *= upHillForceMultiplier;
            }
            else
            {
                // We're facing downhill
