            hoverForce = originalHoverForce; // Reset the hover force
        }
    }

    void FixedUpdate()
    {
        // The hover force and rotation adjustments can occur here.
        // Note the checks and method calls for ramp adjustments should be moved from RampDetection to this script.

        if (isOnRamp)
        {
            // On a ramp - Adjust hover height and ramp alignment
            AlignToRamp(rampNormal, rampAlignmentSpeed); // rampNormal is assumed to be set by the RampDetection script
        }

        // Remaining FixedUpdate logic...
    }

    // Add more methods and logic as needed for handling transitions and other physics interactions...
