using UnityEngine;

[RequireComponent(typeof(Rigidbody))]
public class HoverBoardControl : MonoBehaviour
{
    // Note: The following fields should be set in the Unity Inspector.
    public float hoverForce = 9.81f;
    public float hoverHeight = 2f;
    public GameObject[] hoverPoints;
    public float forwardAcceleration = 8f;
    public float backwardAcceleration = 4f;
    public float turnStrength = 1000f;
    public KeyCode moveForwardKey = KeyCode.W;
    public KeyCode moveBackwardKey = KeyCode.S;
    public KeyCode turnLeftKey = KeyCode.A;
    public KeyCode turnRightKey = KeyCode.D;
    public Transform board;
    public float rampAlignmentSpeed = 5f; // Degrees per second the board will align with ramp
    public float upHillForceMultiplier = 0.5f;
    public float downHillForceMultiplier = 1.5f;
    public float angularDragOnRamp = 2f;

    private float originalAngularDrag;
    private float originalHoverForce;
    private Rigidbody rb;
    private bool isOnRamp;
    private Vector3 rampNormal;
    private float currentThrust;
    private float currentTurn;

    void Awake()
    {
        rb = GetComponent<Rigidbody>();
        originalHoverForce = hoverForce;
        originalAngularDrag = rb.angularDrag;
    }

    void Update()
    {
        float acl = Input.GetAxis("Vertical");
        if (acl > 0.1f)
            currentThrust = forwardAcceleration;
        else if (acl < -0.1f)
            currentThrust = backwardAcceleration;

        currentTurn = 0f;
        if (Input.GetKey(turnLeftKey))
            currentTurn = -turnStrength;
        else if (Input.GetKey(turnRightKey))
            currentTurn = turnStrength;
    }

    void FixedUpdate()
    {
        // Apply hover logic
        RaycastHit hit;
        for (int i = 0; i < hoverPoints.Length; i++)
        {
            var hoverPoint = hoverPoints[i];
            if (Physics.Raycast(hoverPoint.transform.position, -Vector3.up, out hit, hoverHeight))
            {
                rb.AddForceAtPosition(Vector3.up * hoverForce * (1.0f - (hit.distance / hoverHeight)), hoverPoint.transform.position);
            }
            else
            {
                if (transform.position.y > hoverPoint.transform.position.y)
                {
                    rb.AddForceAtPosition(hoverPoint.transform.up * hoverForce, hoverPoint.transform.position);
                }
                else
                {
                    rb.AddForceAtPosition(hoverPoint.transform.up * -hoverForce, hoverPoint.transform.position);
                }
            }
        }

        // Apply thrust force
        rb.AddForce(transform.forward * currentThrust);

        // Apply turning force
        if (currentTurn != 0)
        {
            rb.AddRelativeTorque(Vector3.up * currentTurn);
        }

        // Align to ramp if on one
        AlignToRamp(rampNormal, rampAlignmentSpeed);
    }

    public void SetIsOnRamp(bool onRamp, Vector3 normal)
    {
        isOnRamp = onRamp;
        rampNormal = normal;

        AdjustBoardOnRamp(onRamp);
    }

    private void AlignToRamp(Vector3 normal, float lerpSpeed)
    {
        if (!isOnRamp) return;

        // Calculate the target rotation based on the normal of the ramp
        Vector3 forwardOnRamp = Vector3.ProjectOnPlane(board.forward, normal).normalized;
        Quaternion targetRotation = Quaternion.LookRotation(forwardOnRamp, normal);
        board.rotation = Quaternion.Lerp(board.rotation, targetRotation, Time.fixedDeltaTime * lerpSpeed);
    }

    private void AdjustBoardOnRamp(bool onRamp)
    {
        if (onRamp)
        {
            rb.angularDrag = angularDragOnRamp;
            if (IsMovingUpward())
            {
                hoverForce *= upHillForceMultiplier;
            }
            else
            {
                hoverForce *= downHillForceMultiplier;
            }
        }
        else
        {
            rb.angularDrag = originalAngularDrag;
            hoverForce = originalHoverForce;
        }
    }

    private bool IsMovingUpward()
    {
        Vector3 forward = transform.TransformDirection(Vector3.forward);
        float dotProduct = Vector3.Dot(forward, rampNormal);

        return dotProduct < 0;
    }

    // ... Any additional methods and logic related to other aspects of the hoverboard control...
